private String getDescription(VerbDefinition verb, RouteDefinition route) {
    String description = verb.getTo() != null ? verb.getTo().getDescriptionText() : route.getDescriptionText();
    if (description == null) {
        description = verb.getDescriptionText();
    }
    if (description == null) {
        description = getDescriptionText();
    }
    return description;
}

public static String extractUsername(AccessToken token) {
    String username = token.getPreferredUsername();
    if (username == null) {
        username = token.getName();
    }
    if (username == null) {
        username = token.getSubject();
    }
    return username;
}

protected Boolean omitXmlDeclaration(Message message, Input input) {
    Boolean omitXmlDeclaration = message.getHeader(XmlSignatureConstants.HEADER_OMIT_XML_DECLARATION, Boolean.class);
    if (omitXmlDeclaration == null) {
        omitXmlDeclaration = input.omitXmlDeclaration();
    }
    if (omitXmlDeclaration == null) {
        omitXmlDeclaration = Boolean.FALSE;
    }
    return omitXmlDeclaration;
}

private Transformer getTransformer() throws Exception {
    Transformer t = null;
    if (transformers != null) {
        t = transformers.poll();
    }
    if (t == null) {
        t = createTransformer();
    }
    return t;
}

protected Boolean omitXmlDeclaration(Message message) {
    Boolean omitXmlDeclaration = message.getHeader(XmlSignatureConstants.HEADER_OMIT_XML_DECLARATION, Boolean.class);
    if (omitXmlDeclaration == null) {
        omitXmlDeclaration = getConfiguration().getOmitXmlDeclaration();
    }
    if (omitXmlDeclaration == null) {
        omitXmlDeclaration = Boolean.FALSE;
    }
    LOG.debug("Omit XML declaration: {}", omitXmlDeclaration);
    return omitXmlDeclaration;
}

protected Connector getSocketConnector(Server server, JettyHttpEndpoint endpoint) {
    Connector answer = null;
