public DataFormat createDataFormat(String name, CamelContext context) {
    DataFormat dataFormat = null;

    // lookup in registry first
    DataFormatFactory dataFormatFactory = ResolverHelper.lookupDataFormatFactoryInRegistryWithFallback(context, name);
    if (dataFormatFactory != null) {
        dataFormat = dataFormatFactory.newInstance();
    }

    if (dataFormat == null) {
        dataFormat = createDataFormatFromResource(name, context);
    }

    return dataFormat;
}

public Expression createExpression(CamelContext camelContext, String expression) {
    Expression answer = null;
    if (block != null) {
        answer = block.createExpression(camelContext, expression);
    }
    if (answer == null) {
        // there quoted literal is empty
        answer = ExpressionBuilder.constantExpression("");
    }
    return answer;
}

public InputStream getResourceAsStream(String name) {
    InputStream is = null;
